mapper.select:
SELECT A.SMENU_ID ,A.SMENU_NM ,A.SSCRN_ID ,A.SSCRN_URL_ADR , A.SMENU_AUT_USE_YN , A.RNUM FROM ( SELECT A.SMENU_ID ,A.SMENU_NM ,A.SSCRN_ID ,A.SSCRN_URL_ADR , A.SMENU_AUT_USE_YN , ROWNUM RNUM FROM (
SELECT DISTINCT A.SMENU_ID ,A.SMENU_NM ,A.SSCRN_ID ,B.SSCRN_URL_ADR ,(CASE #{suserGradeCd, jdbcType=VARCHAR} WHEN 'UR0001' THEN 'Y' ELSE ( CASE C.SUSER_GRADE_CD WHEN #{suserGradeCd, jdbcType=VARCHAR} THEN 'Y' ELSE 'N' END ) END) AS SMENU_AUT_USE_YN FROM MST.TB_MENU_BAS A , MST.TB_SCRN_BAS B ,(SELECT SMENU_ID, SUSER_GRADE_CD FROM MST.TB_MENU_AUTH WHERE SUSER_GRADE_CD = #{suserGradeCd, jdbcType=VARCHAR}) C WHERE A.SSCRN_ID = B.SSCRN_ID(+) AND A.SMENU_ID = C.SMENU_ID (+)
AND A.SMENU_ID = #{searchWrd, jdbcType=VARCHAR}
AND A.SMENU_NM ILIKE '%' || #{searchWrd, jdbcType=VARCHAR} || '%'
ORDER BY A.SMENU_ID ) A WHERE ROWNUM <= #{lastIndex} )A WHERE RNUM >= #{firstIndex}

SELECT
count(1) totalCount FROM ( SELECT DISTINCT A.SMENU_ID ,A.SMENU_NM ,A.SSCRN_ID ,B.SSCRN_URL_ADR ,(CASE #{suserGradeCd, jdbcType=VARCHAR} WHEN 'UR0001' THEN 'Y' ELSE ( CASE C.SUSER_GRADE_CD WHEN #{suserGradeCd, jdbcType=VARCHAR} THEN 'Y' ELSE 'N' END ) END) AS SMENU_AUT_USE_YN FROM MST.TB_MENU_BAS A , MST.TB_SCRN_BAS B ,(SELECT SMENU_ID, SUSER_GRADE_CD FROM MST.TB_MENU_AUTH WHERE SUSER_GRADE_CD = #{suserGradeCd, jdbcType=VARCHAR}) C WHERE A.SSCRN_ID = B.SSCRN_ID(+) AND A.SMENU_ID = C.SMENU_ID (+)
AND A.SMENU_ID = #{searchWrd, jdbcType=VARCHAR}
AND A.SMENU_NM ILIKE '%' || #{searchWrd, jdbcType=VARCHAR} || '%'
) A

